# tbf ends before `  tob: {`
# tob ends before `  dochill: {`
# dochill ends before `  abel: {`
# abel ends before `  cory: {`
# cory ends before `  mill: {`
# mill ends before `  naturalism: {`

def inject_before_next(content, end_marker, questions_str):
    # Find `    ]\n  },\n  END_MARKER`
    target = '    ]\n  },\n  ' + end_marker
    if target not in content:
        print(f'MISS: marker "{end_marker}" not found')
        return content
    # Insert new questions before the `\n    ]` that precedes this marker
    pos = content.find(target)
    # The `\n    ]` is right before `\n  },\n  END_MARKER`
    # So we insert before `\n    ]` at pos
    content = content[:pos] + questions_str + content[pos:]
    print(f'OK: questions injected before {end_marker}')
    return content

